```bash
python3 - << 'PY'
import re
p = "llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp"
s = open(p,'r').read()

# Improve the previously inserted two-operand shuffle insertion point logic
pattern = r'''
      // Adjust insertion point to after both operands if they are in the same block\.
      if \(auto \*I1 = dyn_cast<Instruction>\(Op1\)\) \{
        if \(auto \*I2 = dyn_cast<Instruction>\(Op2\)\) \{
          if \(I1->getParent\(\) == I2->getParent\(\)\) \{
            BasicBlock \*BB = I1->getParent\(\);
            auto It1 = I1->getIterator\(\);
            auto It2 = I2->getIterator\(\);
            auto LastIt = It1;
            if \(&\*It2 != &\*It1\) \{
              // Compare order using dominance within the block
              // Advance LastIt to the later of It1/It2\.
              auto BBegin = BB->begin\(\);
              auto dist1 = std::distance\(BBegin, It1\);
              auto dist2 = std::distance\(BBegin, It2\);
              LastIt = dist2 > dist1 \? It2 : It1;
            \}
            Builder\.SetInsertPoint\(BB, std::next\(LastIt\)\);
          \}
        \}
      \}
'''
replacement = r'''
      // Adjust insertion point to after both operands if they are in the same block,
      // and ensure we do not insert before the end of the PHI list.
      if (auto *I1 = dyn_cast<Instruction>(Op1)) {
        if (auto *I2 = dyn_cast<Instruction>(Op2)) {
          if (I1->getParent() == I2->getParent()) {
            BasicBlock *BB = I1->getParent();
            auto It1 = I1->getIterator();
            auto It2 = I2->getIterator();
            auto BBegin = BB->begin();
            auto FirstNonPHIIt = BB->getFirstNonPHIIt();
            // Choose the later of the two operands within the block.
            auto dist1 = std::distance(BBegin, It1);
            auto dist2 = std::distance(BBegin, It2);
            auto LastIt = dist2 > dist1 ? It2 : It1;
            // Ensure insertion point is not before the first non-PHI.
            auto distLast = std::distance(BBegin, LastIt);
            auto distFirstNonPHI = std::distance(BBegin, FirstNonPHIIt);
            if (distLast < distFirstNonPHI)
              LastIt = FirstNonPHIIt;
            Builder.SetInsertPoint(BB, std::next(LastIt));
          }
        }
      }
'''
s_new = re.sub(pattern, replacement, s, flags=re.MULTILINE)

# Improve the single-operand resize shuffle insertion point logic
pattern2 = r'''
      // Ensure insertion point after operand for resize shuffle to maintain dominance\.
      if \(auto \*OI = dyn_cast<Instruction>\(Op\)\) \{
        Builder\.SetInsertPoint\(OI->getParent\(\), std::next\(OI->getIterator\(\)\)\);
      \}
'''
replacement2 = r'''
      // Ensure insertion point after operand for resize shuffle to maintain dominance,
      // and not before the end of the PHI list.
      if (auto *OI = dyn_cast<Instruction>(Op)) {
        BasicBlock *BB = OI->getParent();
        auto It = OI->getIterator();
        auto BBegin = BB->begin();
        auto FirstNonPHIIt = BB->getFirstNonPHIIt();
        auto distOp = std::distance(BBegin, It);
        auto distFirstNonPHI = std::distance(BBegin, FirstNonPHIIt);
        auto InsertIt = distOp < distFirstNonPHI ? FirstNonPHIIt : It;
        Builder.SetInsertPoint(BB, std::next(InsertIt));
      }
'''
s_new = re.sub(pattern2, replacement2, s_new, flags=re.MULTILINE)

if s_new != s:
    open(p,'w').write(s_new)
    print("Refined insertion point logic to respect PHI placement.")
else:
    print("No changes applied; expected patterns not found.")
PY
```

